const input = $input.first().json;
const req = input.body || input;

if (req.debug === true) {
  return {
    json: {
      is_debug: true,
      status: 'debug',
      message: 'Agent orchestrator v4.1 - Self-Annealing Meta-Agent is working!',
      features: [
        'multi-provider', 'hitl-approval', 'plan-mode', 'todo-tracking',
        'session-checkpoint', 'background-tasks', 'async-execution',
        'task-persistence', 'retry-logic', 'context-management', 'streaming-responses',
        'parallel-tool-execution', 'tool-result-caching', 'smart-rate-limiting', 'cost-token-tracking',
        'conversation-memory', 'tool-pipelines', 'webhook-notifications', 'agent-templates',
        'multi-agent-orchestration', 'knowledge-base-rag', 'scheduled-tasks', 'tool-plugins',
        'agent-learning', 'workflow-recording', 'smart-context-injection', 'inter-agent-communication',
        'agent-personas', 'goal-decomposition', 'tool-macros', 'audit-trail', 'adaptive-behavior',
        'gmail-integration', 'sheets-integration', 'sms-integration', 'clickup-integration',
        'n8n-workflow-management', 'enhanced-terminal', 'enhanced-git',
        'self-discovery', 'error-learning', 'meta-introspection', 'self-annealing'
      ],
      version: '4.1.0',
      agent_templates: ['coder', 'researcher', 'analyst', 'writer', 'devops', 'orchestrator'],
      agent_personas: ['senior_engineer', 'rapid_prototyper', 'research_analyst', 'devops_specialist'],
      integrations: {
        gmail: ['gmail_list', 'gmail_read', 'gmail_send', 'gmail_search'],
        sheets: ['sheets_read', 'sheets_write', 'sheets_append'],
        sms: ['sms_send', 'sms_list'],
        clickup: ['clickup_list_tasks', 'clickup_create_task', 'clickup_update_task'],
        n8n: ['n8n_list_workflows', 'n8n_get_workflow', 'n8n_create_workflow', 'n8n_update_workflow', 'n8n_activate_workflow', 'n8n_execute_workflow'],
        git: ['git_clone', 'git_pull', 'git_branch', 'git_log'],
        terminal: ['terminal_multi_command', 'terminal_script']
      },
      meta_agent: {
        capabilities: '/meta/capabilities - List all available tools',
        discover: '/meta/discover - Find new integrations',
        create_tool: '/meta/create-tool - Generate new tool code',
        learn_error: '/meta/learn-error - Store error solutions',
        introspect: '/meta/introspect - Analyze agent behavior',
        suggest: '/meta/suggest - Get improvement suggestions',
        build_workflow: '/agent/build-workflow - Self-replicate new agent workflows'
      },
      timestamp: new Date().toISOString()
    }
  };
}

if (req.continue_session === true && req.session_state) {
  const state = req.session_state;
  state.messages.push({ role: 'user', content: req.message || 'Continue' });
  return {
    json: {
      is_debug: false,
      session_id: req.session_id || state.session_id,
      agent: state.agent,
      task: state.task,
      config: state.config,
      state: state,
      is_continuation: true,
      _background_execution: req._background_execution || false,
      _original_task_id: req._original_task_id || null
    }
  };
}

if (req.resume_session === true && req.session_id) {
  return {
    json: {
      is_debug: false,
      session_id: req.session_id,
      checkpoint_name: req.checkpoint_name || 'default',
      is_resume: true,
      resume_message: req.message || 'Resume from checkpoint',
      _background_execution: req._background_execution || false,
      _original_task_id: req._original_task_id || null
    }
  };
}

const agentPersonas = {
  senior_engineer: {
    traits: ['thorough', 'methodical', 'security-conscious'],
    expertise: ['architecture', 'code-review', 'testing', 'documentation'],
    communication_style: 'technical',
    verbosity: 'detailed'
  },
  rapid_prototyper: {
    traits: ['fast', 'pragmatic', 'iterative'],
    expertise: ['mvp', 'scripting', 'quick-fixes'],
    communication_style: 'casual',
    verbosity: 'minimal'
  },
  research_analyst: {
    traits: ['analytical', 'thorough', 'skeptical'],
    expertise: ['data-analysis', 'market-research', 'competitive-analysis'],
    communication_style: 'professional',
    verbosity: 'detailed'
  },
  devops_specialist: {
    traits: ['cautious', 'systematic', 'documentation-focused'],
    expertise: ['deployment', 'ci-cd', 'monitoring', 'infrastructure'],
    communication_style: 'technical',
    verbosity: 'balanced'
  }
};

const agentTemplates = {
  coder: {
    id: 'coder-agent',
    provider: 'anthropic',
    model: 'claude-sonnet-4-5-20250929',
    tools_available: ['file_read', 'file_write', 'file_edit', 'command', 'grep', 'glob', 'git_status'],
    system_prompt: 'You are an expert software developer. You write clean, efficient, well-documented code.\n\nWhen writing code:\n- Follow best practices and design patterns\n- Include error handling\n- Add helpful comments for complex logic\n\nAvailable tools:\n- file_read: Read a file. Input: {"path": "/absolute/path"}\n- file_write: Write/create a file. Input: {"path": "/path", "content": "text"}\n- file_edit: Edit lines in a file. Input: {"path": "/path", "edits": [{"line_start": 1, "line_end": 2, "new_content": "new text"}]}\n- command: Execute a shell command. Input: {"command": "the command"}\n- grep: Search file contents with regex. Input: {"pattern": "regex", "path": "/dir"}\n- glob: Find files by pattern. Input: {"pattern": "**/*.py", "path": "/dir"}\n- git_status: Get git repository status. Input: {"repo_path": "/path/to/repo"}\n\nUse JSON format: {"action": "tool_name", "input": {...}}\nWhen complete, include TASK_COMPLETE.'
  },
  researcher: {
    id: 'researcher-agent',
    provider: 'anthropic',
    model: 'claude-sonnet-4-5-20250929',
    tools_available: ['web_search', 'web_fetch', 'file_read', 'file_write', 'grep', 'gmail_search', 'gmail_read'],
    system_prompt: 'You are an expert researcher. You find, analyze, and synthesize information effectively.\n\nWhen researching:\n- Search multiple sources for accuracy\n- Verify information when possible\n- Summarize findings clearly\n\nAvailable tools:\n- web_search: Search the web. Input: {"query": "search terms", "max_results": 10}\n- web_fetch: Fetch content from a URL. Input: {"url": "https://..."}\n- file_read: Read a file. Input: {"path": "/absolute/path"}\n- file_write: Write/create a file. Input: {"path": "/path", "content": "text"}\n- grep: Search file contents. Input: {"pattern": "regex", "path": "/dir"}\n- gmail_search: Search emails. Input: {"query": "search terms"}\n- gmail_read: Read an email. Input: {"message_id": "id"}\n\nUse JSON format: {"action": "tool_name", "input": {...}}\nWhen complete, include TASK_COMPLETE.'
  },
  analyst: {
    id: 'analyst-agent',
    provider: 'anthropic',
    model: 'claude-sonnet-4-5-20250929',
    tools_available: ['file_read', 'command', 'grep', 'glob', 'file_write', 'sheets_read', 'sheets_write'],
    system_prompt: 'You are an expert data analyst. You analyze data, identify patterns, and provide actionable insights.\n\nWhen analyzing:\n- Look for trends and patterns\n- Calculate relevant statistics\n- Provide clear recommendations\n\nAvailable tools:\n- file_read: Read a file. Input: {"path": "/absolute/path"}\n- command: Execute a shell command. Input: {"command": "the command"}\n- grep: Search file contents. Input: {"pattern": "regex", "path": "/dir"}\n- glob: Find files by pattern. Input: {"pattern": "**/*.csv", "path": "/dir"}\n- file_write: Write/create a file. Input: {"path": "/path", "content": "text"}\n- sheets_read: Read from Google Sheets. Input: {"range": "Sheet1!A1:Z100"}\n- sheets_write: Write to Google Sheets. Input: {"range": "Sheet1!A1", "values": [[...]]}\n\nUse JSON format: {"action": "tool_name", "input": {...}}\nWhen complete, include TASK_COMPLETE.'
  },
  writer: {
    id: 'writer-agent',
    provider: 'anthropic',
    model: 'claude-sonnet-4-5-20250929',
    tools_available: ['file_read', 'file_write', 'web_search', 'web_fetch', 'gmail_send'],
    system_prompt: 'You are an expert content writer. You create engaging, clear, and well-structured content.\n\nWhen writing:\n- Use clear and concise language\n- Structure content logically\n- Adapt tone to the audience\n\nAvailable tools:\n- file_read: Read a file. Input: {"path": "/absolute/path"}\n- file_write: Write/create a file. Input: {"path": "/path", "content": "text"}\n- web_search: Search the web. Input: {"query": "search terms"}\n- web_fetch: Fetch content from a URL. Input: {"url": "https://..."}\n- gmail_send: Send an email. Input: {"to": "email", "subject": "...", "body": "..."}\n\nUse JSON format: {"action": "tool_name", "input": {...}}\nWhen complete, include TASK_COMPLETE.'
  },
  devops: {
    id: 'devops-agent',
    provider: 'anthropic',
    model: 'claude-sonnet-4-5-20250929',
    tools_available: ['command', 'file_read', 'file_write', 'file_edit', 'git_status', 'grep', 'glob', 'git_clone', 'git_pull', 'git_branch', 'terminal_multi_command'],
    system_prompt: 'You are an expert DevOps engineer. You manage infrastructure, deployments, and automation.\n\nWhen working:\n- Follow security best practices\n- Document all changes\n- Be cautious with destructive commands\n\nAvailable tools:\n- command: Execute a shell command. Input: {"command": "the command"}\n- file_read: Read a file. Input: {"path": "/absolute/path"}\n- file_write: Write/create a file. Input: {"path": "/path", "content": "text"}\n- file_edit: Edit lines in a file. Input: {"path": "/path", "edits": [...]}\n- git_status: Get git repository status. Input: {"repo_path": "/path/to/repo"}\n- grep: Search file contents. Input: {"pattern": "regex", "path": "/dir"}\n- glob: Find files by pattern. Input: {"pattern": "**/*.yml", "path": "/dir"}\n- git_clone: Clone a repository. Input: {"url": "...", "path": "..."}\n- git_pull: Pull from remote. Input: {"repo_path": "..."}\n- git_branch: Manage branches. Input: {"action": "list|create|switch", "branch": "..."}\n- terminal_multi_command: Run multiple commands. Input: {"commands": ["cmd1", "cmd2"]}\n\nUse JSON format: {"action": "tool_name", "input": {...}}\nWhen complete, include TASK_COMPLETE.'
  },
  orchestrator: {
    id: 'orchestrator-agent',
    provider: 'anthropic',
    model: 'claude-sonnet-4-5-20250929',
    tools_available: ['file_read', 'file_write', 'command', 'grep', 'glob', 'git_status', 'n8n_list_workflows', 'n8n_create_workflow', 'meta_capabilities', 'meta_discover'],
    system_prompt: 'You are a task orchestrator. You break down complex tasks into sub-tasks and delegate to specialized agents. You can also build new agent workflows.\n\nWhen orchestrating:\n- Analyze the task complexity\n- Identify sub-tasks that can run in parallel\n- Coordinate results from sub-agents\n- Synthesize final output\n- Build new workflows when needed\n\nAvailable tools:\n- file_read: Read a file. Input: {"path": "/absolute/path"}\n- file_write: Write/create a file. Input: {"path": "/path", "content": "text"}\n- command: Execute a shell command. Input: {"command": "the command"}\n- grep: Search file contents. Input: {"pattern": "regex", "path": "/dir"}\n- glob: Find files by pattern. Input: {"pattern": "**/*", "path": "/dir"}\n- git_status: Get git repository status. Input: {"repo_path": "/path/to/repo"}\n- n8n_list_workflows: List n8n workflows. Input: {}\n- n8n_create_workflow: Create new workflow. Input: {"name": "...", "nodes": [...], "connections": {...}}\n- meta_capabilities: List all available capabilities. Input: {}\n- meta_discover: Discover new tools. Input: {}\n\nUse JSON format: {"action": "tool_name", "input": {...}}\nWhen complete, include TASK_COMPLETE.'
  }
};

const allTools = [
  'file_read', 'file_write', 'file_edit', 'command', 'git_status', 'web_fetch', 'grep', 'glob', 'web_search', 'todo', 'checkpoint',
  'gmail_list', 'gmail_read', 'gmail_send', 'gmail_search',
  'sheets_read', 'sheets_write', 'sheets_append',
  'sms_send', 'sms_list',
  'clickup_list_tasks', 'clickup_create_task', 'clickup_update_task',
  'n8n_list_workflows', 'n8n_get_workflow', 'n8n_create_workflow', 'n8n_update_workflow', 'n8n_activate_workflow', 'n8n_execute_workflow',
  'git_clone', 'git_pull', 'git_branch', 'git_log',
  'terminal_multi_command', 'terminal_script',
  'meta_capabilities', 'meta_discover', 'meta_create_tool', 'meta_learn_error', 'meta_find_solution', 'meta_introspect', 'meta_suggest', 'agent_build_workflow'
];

const approvalTools = ['command', 'file_write', 'file_edit', 'gmail_send', 'sms_send', 'clickup_create_task', 'n8n_create_workflow', 'n8n_activate_workflow', 'terminal_script'];
const dangerousPatterns = ['rm -rf', 'rm -r', 'rmdir', 'git push', 'git push --force', 'kill', 'pkill', 'killall', 'reboot', 'shutdown', 'chmod 777', 'chown', 'dd if=', 'mkfs', ':(){', '> /dev/'];

let personaEnhancement = '';
if (req.persona && agentPersonas[req.persona]) {
  const persona = agentPersonas[req.persona];
  personaEnhancement = `\n\nPersona traits: ${persona.traits.join(', ')}. Expertise: ${persona.expertise.join(', ')}. Communication style: ${persona.communication_style}. Verbosity: ${persona.verbosity}.`;
}

let agent;
if (req.template && agentTemplates[req.template]) {
  agent = { ...agentTemplates[req.template] };
  if (req.agent) {
    Object.assign(agent, req.agent);
  }
} else {
  agent = req.agent || { id: 'meta-agent-v1', provider: 'anthropic', model: 'claude-sonnet-4-5-20250929', tools_available: allTools };
}

if (!agent.provider) agent.provider = 'anthropic';
if (!agent.model) agent.model = agent.provider === 'xai' ? 'grok-2-latest' : 'claude-sonnet-4-5-20250929';
if (!agent.tools_available) agent.tools_available = allTools;

const toolDocs = {
  file_read: '- file_read: Read a file. Input: {"path": "/absolute/path"}',
  file_write: '- file_write: Write/create a file. Input: {"path": "/path", "content": "text"}',
  file_edit: '- file_edit: Edit lines in a file. Input: {"path": "/path", "edits": [{"line_start": 1, "line_end": 2, "new_content": "new text"}]}',
  command: '- command: Execute a shell command. Input: {"command": "the command"}',
  git_status: '- git_status: Get git repository status. Input: {"repo_path": "/path/to/repo"}',
  web_fetch: '- web_fetch: Fetch content from a URL. Input: {"url": "https://..."}',
  grep: '- grep: Search file contents with regex. Input: {"pattern": "regex", "path": "/dir", "type": "py", "context": 2}',
  glob: '- glob: Find files by pattern. Input: {"pattern": "**/*.py", "path": "/dir"}',
  web_search: '- web_search: Search the web. Input: {"query": "search terms", "max_results": 10}',
  todo: '- todo: Manage task list. Input: {"operation": "add|update|list|delete", "content": "task", "id": "id", "status": "pending|in_progress|completed"}',
  checkpoint: '- checkpoint: Save session state for later resume. Input: {"name": "optional_checkpoint_name"}',
  gmail_list: '- gmail_list: List emails. Input: {"max_results": 10, "query": "is:unread"}',
  gmail_read: '- gmail_read: Read an email. Input: {"message_id": "abc123"}',
  gmail_send: '- gmail_send: Send an email. Input: {"to": "email@example.com", "subject": "Subject", "body": "Email body"}',
  gmail_search: '- gmail_search: Search emails. Input: {"query": "from:someone@example.com", "max_results": 20}',
  sheets_read: '- sheets_read: Read from Google Sheets. Input: {"spreadsheet_id": "...", "range": "Sheet1!A1:Z100"}',
  sheets_write: '- sheets_write: Write to Google Sheets. Input: {"spreadsheet_id": "...", "range": "Sheet1!A1", "values": [["cell1", "cell2"]]}',
  sheets_append: '- sheets_append: Append rows to Google Sheets. Input: {"spreadsheet_id": "...", "range": "Sheet1!A1", "values": [["row1col1", "row1col2"]]}',
  sms_send: '- sms_send: Send SMS via Twilio. Input: {"to": "+1234567890", "body": "Message text"}',
  sms_list: '- sms_list: List SMS messages. Input: {"limit": 20, "direction": "inbound|outbound"}',
  clickup_list_tasks: '- clickup_list_tasks: List tasks from ClickUp. Input: {"list_id": "..."}',
  clickup_create_task: '- clickup_create_task: Create a ClickUp task. Input: {"name": "Task name", "description": "..."}',
  clickup_update_task: '- clickup_update_task: Update a ClickUp task. Input: {"task_id": "...", "name": "...", "status": "..."}',
  n8n_list_workflows: '- n8n_list_workflows: List n8n workflows. Input: {}',
  n8n_get_workflow: '- n8n_get_workflow: Get a workflow. Input: {"workflow_id": "..."}',
  n8n_create_workflow: '- n8n_create_workflow: Create a workflow. Input: {"name": "...", "nodes": [...], "connections": {...}}',
  n8n_update_workflow: '- n8n_update_workflow: Update a workflow. Input: {"workflow_id": "...", "nodes": [...]}',
  n8n_activate_workflow: '- n8n_activate_workflow: Activate/deactivate workflow. Input: {"workflow_id": "...", "active": true}',
  n8n_execute_workflow: '- n8n_execute_workflow: Execute a workflow. Input: {"workflow_id": "...", "data": {...}}',
  git_clone: '- git_clone: Clone a repository. Input: {"url": "https://...", "path": "/dest/path"}',
  git_pull: '- git_pull: Pull from remote. Input: {"repo_path": "/path/to/repo"}',
  git_branch: '- git_branch: Manage branches. Input: {"repo_path": "...", "action": "list|create|switch|delete", "branch": "name"}',
  git_log: '- git_log: Get commit log. Input: {"repo_path": "...", "limit": 10}',
  terminal_multi_command: '- terminal_multi_command: Run multiple commands. Input: {"commands": ["cmd1", "cmd2"], "mode": "sequential|parallel", "stop_on_error": true}',
  terminal_script: '- terminal_script: Run a shell script. Input: {"script": "#!/bin/bash\\n...", "interpreter": "/bin/bash"}',
  meta_capabilities: '- meta_capabilities: List all available capabilities. Input: {}',
  meta_discover: '- meta_discover: Discover new integrations. Input: {}',
  meta_create_tool: '- meta_create_tool: Generate new tool code. Input: {"name": "tool_name", "description": "..."}',
  meta_learn_error: '- meta_learn_error: Store solution to error. Input: {"error_pattern": "...", "solution": "..."}',
  meta_find_solution: '- meta_find_solution: Find stored error solution. Input: {"error_message": "..."}',
  meta_introspect: '- meta_introspect: Analyze agent behavior. Input: {}',
  meta_suggest: '- meta_suggest: Get improvement suggestions. Input: {}',
  agent_build_workflow: '- agent_build_workflow: Build new agent workflow. Input: {"name": "...", "webhook_path": "...", "tools": [...]}'
};

const availableToolDocs = agent.tools_available.map(t => toolDocs[t] || ('- ' + t)).join('\n');

const planMode = req.config?.plan_mode === true;
const backgroundMode = req.background === true && !req._background_execution;

let systemPrompt = agent.system_prompt;
if (!systemPrompt) {
  if (planMode) {
    systemPrompt = 'You are a helpful AI assistant that can perform actions using tools.\n\nIMPORTANT: PLAN MODE is enabled. You MUST first create a plan before executing any actions.\n\nTo create a plan, respond with:\n{"action": "plan", "input": {"title": "Plan Title", "steps": ["Step 1 description", "Step 2 description", ...]}}\n\nAfter your plan is approved, you will execute each step using the available tools.\n\nAvailable tools:\n' + availableToolDocs + '\n\nWhen you need to use a tool, respond with:\n{"action": "tool_name", "input": {"key": "value"}}\n\nDo NOT use XML tags. ONLY use JSON format.\nAfter using a tool, wait for the result before continuing.\nWhen the task is fully complete, include TASK_COMPLETE in your response.';
  } else {
    systemPrompt = 'You are a powerful AI assistant with access to many tools and integrations. You can read/send emails, manage spreadsheets, send SMS, manage CRM tasks, control n8n workflows, and more.\n\nIMPORTANT: When you need to use a tool, you MUST respond with ONLY a JSON object in this exact format:\n{"action": "tool_name", "input": {"key": "value"}}\n\nAvailable tools:\n' + availableToolDocs + '\n\nDo NOT use XML tags or any other format. ONLY use the JSON format above.\nAfter using a tool, wait for the result before continuing.\nWhen the task is fully complete, include TASK_COMPLETE in your response.';
  }
}

if (personaEnhancement) {
  systemPrompt += personaEnhancement;
}

let task;
if (typeof req.task === 'string') {
  task = { objective: req.task, context: '/home/ec2-user/dev-sandbox' };
} else {
  task = req.task || { objective: 'List available capabilities and suggest what I can help with', context: '/home/ec2-user' };
}

const config = {
  max_iterations: 10,
  require_approval_for: req.config?.require_approval_for || approvalTools,
  dangerous_patterns: dangerousPatterns,
  approval_timeout_seconds: 300,
  plan_mode: planMode,
  retry: { enabled: req.config?.retry?.enabled !== false, max_retries: req.config?.retry?.max_retries || 3, base_delay: req.config?.retry?.base_delay || 1.0 },
  context: { auto_truncate: req.config?.context?.auto_truncate !== false, max_tokens: req.config?.context?.max_tokens || 120000, preserve_first: 1, preserve_last: 5 },
  streaming: { enabled: req.config?.streaming?.enabled || false },
  parallel: { enabled: req.config?.parallel?.enabled !== false, max_workers: req.config?.parallel?.max_workers || 4, timeout: 30 },
  cache: { enabled: req.config?.cache?.enabled !== false, ttl: req.config?.cache?.ttl || 300, max_size: 100 },
  ratelimit: { enabled: req.config?.ratelimit?.enabled !== false, rate: 10.0, capacity: 20 },
  cost: { enabled: req.config?.cost?.enabled !== false, budget_limit: null, track_tokens: true },
  memory: { enabled: req.config?.memory?.enabled !== false, max_messages: 100 },
  webhook: { url: req.config?.webhook?.url || null, events: ['task_complete', 'task_error'] },
  orchestration: { enabled: req.config?.orchestration?.enabled !== false, max_sub_agents: 5, strategy: 'parallel' },
  knowledge_base: { kb_id: req.config?.knowledge_base?.kb_id || null, auto_context: true },
  learning: { enabled: req.config?.learning?.enabled !== false, record_outcomes: true, apply_recommendations: true },
  recording: { enabled: req.config?.recording?.enabled || false, auto_record: false },
  context_injection: { enabled: req.config?.context_injection?.enabled !== false, max_chunks: 5 },
  inter_agent: { enabled: req.config?.inter_agent?.enabled !== false, orchestration_id: null },
  persona: { id: req.persona || null, custom_traits: req.config?.persona?.custom_traits || [] },
  goals: { enabled: req.config?.goals?.enabled !== false, auto_decompose: false, strategy: 'sequential' },
  macros: { enabled: req.config?.macros?.enabled !== false, allowed_macros: [] },
  audit: { enabled: req.config?.audit?.enabled !== false, log_inputs: true, log_outputs: true },
  adaptive: { enabled: req.config?.adaptive?.enabled !== false, learning_rate: 0.1, apply_adaptations: true },
  meta_agent: {
    self_discovery: req.config?.meta_agent?.self_discovery !== false,
    error_learning: req.config?.meta_agent?.error_learning !== false,
    auto_suggest: req.config?.meta_agent?.auto_suggest || false
  },
  ...req.config
};

let initialMessage = 'Task: ' + task.objective + '\nContext: ' + (task.context || 'none') + '\n\n';
if (planMode) {
  initialMessage += 'PLAN MODE: First, create a plan for how you will accomplish this task. The plan will be reviewed before execution.';
} else {
  initialMessage += 'Remember: Use ONLY JSON format for tool calls: {"action": "tool_name", "input": {...}}';
}

const sessionId = req.session_id || 'session_' + Date.now();
const taskId = backgroundMode ? 'task_' + Date.now().toString(36) + Math.random().toString(36).substr(2, 6) : null;

const estimateTokens = (text) => text ? Math.ceil(text.length / 4) : 0;
const initialTokenEstimate = estimateTokens(systemPrompt) + estimateTokens(initialMessage);

return {
  json: {
    is_debug: false,
    session_id: sessionId,
    task_id: taskId,
    background_mode: backgroundMode,
    template_used: req.template || null,
    persona_used: req.persona || null,
    agent: { ...agent, system_prompt: systemPrompt },
    task: task,
    config: config,
    state: {
      iteration: 0,
      history: [],
      approvals: [],
      plan: null,
      plan_approved: false,
      current_step: 0,
      todos: [],
      messages: [{ role: 'user', content: initialMessage }],
      token_estimate: initialTokenEstimate,
      context_truncated: false,
      cost_tracker: { input_tokens: 0, output_tokens: 0, total_cost: 0.0, tool_calls: 0 },
      learning_applied: false,
