  created_at: new Date().toISOString(),
  timeout_seconds: d.config.approval_timeout_seconds || 300
};

// Store in state for tracking
d.state.pending_approval = approvalRequest;

return { json: { ...d, approval_request: approvalRequest } };

// Process approval response from webhook
const webhookData = $input.first().json;
const prevData = $('Format Approval').first().json;

// Check if approved (webhook body should contain { approved: true/false })
const approved = webhookData.body?.approved === true || webhookData.approved === true;
const reason = webhookData.body?.reason || webhookData.reason || '';
const isPlan = prevData.is_plan;

prevData.state.approvals.push({
  approval_id: prevData.approval_request?.approval_id,
  action_type: prevData.action_type,
  is_plan: isPlan,
  approved: approved,
  reason: reason,
