// Exponential backoff retry logic
const input = $input.first().json;
const maxRetries = 3;
const baseDelay = 1000; // 1 second

// Get current retry count from state
let retryCount = input.state?.retry_count || 0;
const lastError = input.tool_result?.error || input.error;

// Check if error is retryable
const retryableErrors = ['ECONNRESET', 'ETIMEDOUT', 'ECONNREFUSED', 'rate limit', 'timeout', 'temporary'];
const isRetryable = retryableErrors.some(e => 
  (lastError?.toLowerCase() || '').includes(e.toLowerCase())
);

if (!isRetryable || retryCount >= maxRetries) {
  // Not retryable or max retries reached
  return {
    json: {
      ...input,
      should_retry: false,
      retry_exhausted: retryCount >= maxRetries,
      final_error: lastError
    }
  };
}

// Calculate delay with exponential backoff
const delay = baseDelay * Math.pow(2, retryCount);

// Update retry count in state
if (!input.state) input.state = {};
input.state.retry_count = retryCount + 1;

return {
  json: {
    ...input,
    should_retry: true,
    retry_count: retryCount + 1,
    retry_delay_ms: delay,
    retry_message: `Retrying in ${delay}ms (attempt ${retryCount + 1}/${maxRetries})`
  }
};

