  'beta.multi_region': { enabled: false, rollout: 0 }
};

// Calculate user's feature bucket (0-100) based on user ID
const userId = auth.user || 'anonymous';
let userBucket = 0;
for (let i = 0; i < userId.length; i++) {
  userBucket = (userBucket + userId.charCodeAt(i)) % 100;
}

// Determine which features are enabled for this user
const enabledFeatures = {};
const disabledFeatures = [];

for (const [feature, config] of Object.entries(FEATURES)) {
  const isEnabled = config.enabled && userBucket < config.rollout;
  enabledFeatures[feature] = isEnabled;
  if (!isEnabled && config.enabled) {
    disabledFeatures.push(feature);
  }
}

// Check if any requested features are disabled
const requestedFeatures = body.features || [];
const unavailableFeatures = requestedFeatures.filter(f => !enabledFeatures[f]);

return {
  json: {
    ...input,
    feature_flags: {
      user_bucket: userBucket,
      enabled: enabledFeatures,
      disabled_for_user: disabledFeatures,
      requested: requestedFeatures,
      unavailable: unavailableFeatures,
      all_requested_available: unavailableFeatures.length === 0
    }
