// A/B Testing System
const input = $input.first().json;
const auth = input.auth || {};
const featureFlags = input.feature_flags || {};

// Active experiments
const EXPERIMENTS = {
  'prompt_optimization': {
    enabled: true,
    variants: {
      'control': { weight: 50, config: { system_prompt_version: 'v1' } },
      'treatment_a': { weight: 25, config: { system_prompt_version: 'v2_concise' } },
      'treatment_b': { weight: 25, config: { system_prompt_version: 'v2_detailed' } }
    }
  },
  'model_comparison': {
    enabled: true,
    variants: {
      'claude_sonnet': { weight: 80, config: { model: 'claude-sonnet-4-5-20250929' } },
      'claude_haiku': { weight: 20, config: { model: 'claude-haiku-4-5-20251001' } }
    }
  },
  'timeout_optimization': {
    enabled: true,
    variants: {
      'standard': { weight: 70, config: { timeout: 120000 } },
      'extended': { weight: 30, config: { timeout: 180000 } }
    }
  }
};

// Assign user to experiment variants based on user ID
const userId = auth.user || input.deduplication?.request_id || 'anonymous';
const assignments = {};

for (const [expName, exp] of Object.entries(EXPERIMENTS)) {
  if (!exp.enabled) continue;

  // Generate deterministic bucket for this user+experiment
  let bucket = 0;
  const seed = userId + expName;
  for (let i = 0; i < seed.length; i++) {
    bucket = (bucket * 31 + seed.charCodeAt(i)) % 100;
  }

  // Assign variant based on weights
  let cumWeight = 0;
  for (const [variantName, variant] of Object.entries(exp.variants)) {
    cumWeight += variant.weight;
    if (bucket < cumWeight) {
      assignments[expName] = {
        variant: variantName,
        config: variant.config,
        bucket: bucket
      };
      break;
    }
  }
}

// Apply experiment configs to request
let experimentConfigs = {};
for (const [expName, assignment] of Object.entries(assignments)) {
  experimentConfigs = { ...experimentConfigs, ...assignment.config };
}

return {
  json: {
    ...input,
    ab_testing: {
      user_id: userId,
      assignments: assignments,
      applied_configs: experimentConfigs,
      experiment_count: Object.keys(assignments).length
    },
    // Merge experiment configs into main config
    experiment_config: experimentConfigs
  }
};

