// Intelligent Caching Layer
const input = $input.first().json;
const body = input.body || {};

// Cache configuration
const CACHE_CONFIG = {
  enabled: true,
  default_ttl: 300,  // 5 minutes
  max_size: 1000,

  // Cache policies by operation type
  policies: {
    read: { ttl: 600, enabled: true },      // 10 min for reads
    search: { ttl: 300, enabled: true },    // 5 min for searches
    write: { ttl: 0, enabled: false },      // Never cache writes
    execute: { ttl: 0, enabled: false }     // Never cache executions
  }
};

// Generate cache key from request
const generateCacheKey = (task, config) => {
  const taskStr = typeof task === 'string' ? task : JSON.stringify(task);
  const configStr = JSON.stringify(config || {});
  // Simple hash function
  let hash = 0;
  const str = taskStr + configStr;
  for (let i = 0; i < str.length; i++) {
    const char = str.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash;
  }
  return `cache_${Math.abs(hash).toString(16)}`;
};

// Determine operation type
const taskText = (typeof body.task === 'string' ? body.task : body.task?.objective || '').toLowerCase();
const operationType = taskText.includes('read') || taskText.includes('get') || taskText.includes('list') ? 'read' :
                      taskText.includes('search') || taskText.includes('find') || taskText.includes('grep') ? 'search' :
                      taskText.includes('write') || taskText.includes('create') || taskText.includes('edit') ? 'write' : 'execute';

const policy = CACHE_CONFIG.policies[operationType];
const cacheKey = generateCacheKey(body.task, body.config);

// Check cache (simulated - would use Redis in production)
const CACHE_STORE = $env.CACHE_STORE ? JSON.parse($env.CACHE_STORE) : {};
const cachedEntry = CACHE_STORE[cacheKey];
const now = Date.now();

let cacheResult = {
  key: cacheKey,
  operation_type: operationType,
  policy: policy,
  hit: false,
  cached_at: null,
  expires_at: null,
  age_seconds: null
};

if (policy.enabled && cachedEntry) {
  const age = (now - cachedEntry.cached_at) / 1000;
  if (age < policy.ttl) {
    cacheResult.hit = true;
    cacheResult.cached_at = new Date(cachedEntry.cached_at).toISOString();
    cacheResult.expires_at = new Date(cachedEntry.cached_at + policy.ttl * 1000).toISOString();
    cacheResult.age_seconds = Math.round(age);
    cacheResult.cached_response = cachedEntry.response;
  }
}

// If cache hit, we could short-circuit here
// For now, we just record the cache status

return {
  json: {
    ...input,
    cache: cacheResult,
    skip_execution: cacheResult.hit  // Signal to skip if cached
  }
};

// Request Throttling and Backpressure Controller
const input = $input.first().json;
const auth = input.auth || {};
const rbac = input.rbac || {};

// Throttle configuration per tier
const THROTTLE_TIERS = {
  admin: {
    requests_per_second: 100,
    burst_limit: 200,
    queue_limit: 500,
    priority_boost: 2
  },
  developer: {
    requests_per_second: 20,
    burst_limit: 50,
    queue_limit: 100,
    priority_boost: 1
  },
  user: {
    requests_per_second: 5,
    burst_limit: 10,
    queue_limit: 20,
    priority_boost: 0
  },
  anonymous: {
    requests_per_second: 1,
    burst_limit: 3,
    queue_limit: 5,
    priority_boost: -1
  }
};

// Get user's tier
const userRole = (auth.roles || ['anonymous'])[0];
const tier = THROTTLE_TIERS[userRole] || THROTTLE_TIERS.anonymous;

// System load (simulated - would measure actual load)
const systemLoad = {
  cpu_percent: 45,
  memory_percent: 60,
  queue_depth: 15,
  active_requests: 8
};

// Calculate backpressure
const loadFactor = Math.max(
  systemLoad.cpu_percent / 100,
  systemLoad.memory_percent / 100,
  systemLoad.queue_depth / tier.queue_limit
);

// Throttle decision
const throttleResult = {
  tier: userRole,
  config: tier,
  system_load: systemLoad,
  load_factor: loadFactor,

  // Actions
  should_throttle: loadFactor > 0.8,
  should_queue: loadFactor > 0.5 && loadFactor <= 0.8,
  should_reject: loadFactor > 0.95,

  // Backpressure signals
  backpressure: {
    delay_ms: loadFactor > 0.5 ? Math.floor(loadFactor * 1000) : 0,
    retry_after: loadFactor > 0.8 ? Math.ceil(loadFactor * 10) : null,
    queue_position: loadFactor > 0.5 ? systemLoad.queue_depth + 1 : null
  },

  // Adjusted priority based on tier
  adjusted_priority: Math.max(1, (input.priority_queue?.priority || 3) - tier.priority_boost)
};

// If should reject, return early
if (throttleResult.should_reject) {
  return {
    json: {
      success: false,
      error: 'SERVICE_OVERLOADED',
      message: 'System is under heavy load. Please retry later.',
      retry_after_seconds: throttleResult.backpressure.retry_after,
      throttle: throttleResult
    }
  };
}

return {
  json: {
    ...input,
    throttle: throttleResult,
    // Update priority based on throttle decision
    priority_queue: {
      ...input.priority_queue,
      priority: throttleResult.adjusted_priority
    }
  }
};

