// Request Replay Engine - Replay failed requests from audit log
const input = $input.first().json;

// Replay configuration
const REPLAY_CONFIG = {
  enabled: true,
  max_replays: 3,
  replay_delay_ms: 1000,
  eligible_errors: [
    'TIMEOUT',
    'RATE_LIMIT',
    'TEMPORARY_FAILURE',
    'CONNECTION_ERROR'
  ],
  // Errors that should never be replayed
  excluded_errors: [
    'AUTHORIZATION_FAILED',
    'INVALID_INPUT',
    'PERMISSION_DENIED',
    'BUDGET_EXCEEDED'
  ]
};

// Check if this request is a replay
const isReplay = input.replay?.is_replay || false;
const replayCount = input.replay?.count || 0;

// Determine if request is eligible for replay
const currentError = input.error?.code || input.state?.last_error?.code;
const isEligible = currentError &&
  REPLAY_CONFIG.eligible_errors.includes(currentError) &&
  !REPLAY_CONFIG.excluded_errors.includes(currentError) &&
  replayCount < REPLAY_CONFIG.max_replays;

// Build replay context
const replayContext = {
  is_replay: isReplay,
  replay_count: replayCount,
  max_replays: REPLAY_CONFIG.max_replays,

  // Current request eligibility
  current_error: currentError,
  eligible_for_replay: isEligible,

  // If eligible, prepare replay metadata
  replay_metadata: isEligible ? {
    original_request_id: input.deduplication?.request_id,
    original_trace_id: input.trace?.trace_id,
    error_that_triggered: currentError,
    scheduled_replay_at: new Date(Date.now() + REPLAY_CONFIG.replay_delay_ms * Math.pow(2, replayCount)).toISOString(),
    backoff_multiplier: Math.pow(2, replayCount)
  } : null,

  // Replay history (from original request)
  history: input.replay?.history || []
};

// Add current attempt to history if this is a replay
if (isReplay) {
  replayContext.history.push({
    attempt: replayCount,
    timestamp: new Date().toISOString(),
    error: currentError,
    success: !currentError
  });
}

return {
  json: {
    ...input,
    replay: replayContext
  }
};

// Canary Deployment Controller - Safe rollouts with traffic splitting
const input = $input.first().json;
const auth = input.auth || {};
const featureFlags = input.feature_flags || {};

// Canary configuration
const CANARY_DEPLOYMENTS = {
  'v4.4-websocket': {
    enabled: true,
    traffic_percent: 10,  // 10% of traffic
    target_version: '4.4.0',
    fallback_version: '4.3.0',
    metrics_window_minutes: 60,
    success_threshold: 0.95,  // 95% success rate required
    rollback_on_error_rate: 0.1  // Rollback if >10% errors
  },
  'new-model-test': {
    enabled: true,
    traffic_percent: 5,
    target_version: 'claude-opus-4-5',
    fallback_version: 'claude-sonnet-4-5',
    metrics_window_minutes: 120,
    success_threshold: 0.90,
    rollback_on_error_rate: 0.15
  }
};

// Determine user's canary bucket (0-100) based on user ID
const userId = auth.user || input.deduplication?.request_id || 'anonymous';
let userBucket = 0;
for (let i = 0; i < userId.length; i++) {
  userBucket = (userBucket * 31 + userId.charCodeAt(i)) % 100;
}

// Check each canary deployment
const canaryAssignments = {};
const activeCanaries = [];

for (const [canaryName, config] of Object.entries(CANARY_DEPLOYMENTS)) {
  if (!config.enabled) continue;

  const inCanary = userBucket < config.traffic_percent;

  canaryAssignments[canaryName] = {
    in_canary: inCanary,
    version: inCanary ? config.target_version : config.fallback_version,
    traffic_percent: config.traffic_percent,
    user_bucket: userBucket
  };

  if (inCanary) {
    activeCanaries.push(canaryName);
  }
}

// Canary metrics (simulated - would query actual metrics)
const canaryMetrics = {
  'v4.4-websocket': {
    requests_total: 1000,
    success_rate: 0.97,
    error_rate: 0.03,
    avg_latency_ms: 150,
    status: 'healthy'
  }
};

return {
  json: {
    ...input,
    canary: {
      user_bucket: userBucket,
      assignments: canaryAssignments,
      active_canaries: activeCanaries,
      metrics: canaryMetrics,

      // Applied configuration based on canaries
      applied_version: activeCanaries.length > 0
        ? canaryAssignments[activeCanaries[0]].version
        : '4.3.0'
    }
  }
};

// SLA Monitoring - Track and alert on service level agreements
const input = $input.first().json;

// SLA definitions
const SLA_DEFINITIONS = {
  'response_time': {
    name: 'Response Time SLA',
    target_ms: 5000,  // 5 seconds
    warning_ms: 3000,
    critical_ms: 10000,
    measurement: 'p95'  // 95th percentile
  },
  'availability': {
    name: 'Availability SLA',
    target_percent: 99.9,
    warning_percent: 99.5,
    critical_percent: 99.0,
    measurement_window: '24h'
  },
  'error_rate': {
    name: 'Error Rate SLA',
    target_percent: 1.0,  // Max 1% errors
    warning_percent: 0.5,
    critical_percent: 2.0
  },
  'throughput': {
    name: 'Throughput SLA',
    target_rps: 100,  // Requests per second
    warning_rps: 80,
    critical_rps: 50
  }
};

// Calculate current request metrics
const requestStartTime = input.trace?.span?.start_time
  ? new Date(input.trace.span.start_time).getTime()
  : Date.now() - 1000;
const currentDuration = Date.now() - requestStartTime;
const isError = input.state?.status === 'failed' || input.error;

// SLA status check
const slaStatus = {};
const slaViolations = [];
const slaWarnings = [];

// Check response time SLA
const rtSla = SLA_DEFINITIONS.response_time;
if (currentDuration > rtSla.critical_ms) {
  slaViolations.push({
    sla: 'response_time',
    severity: 'critical',
    current: currentDuration,
    target: rtSla.target_ms,
    message: `Response time ${currentDuration}ms exceeds critical threshold ${rtSla.critical_ms}ms`
  });
} else if (currentDuration > rtSla.warning_ms) {
  slaWarnings.push({
    sla: 'response_time',
    severity: 'warning',
    current: currentDuration,
    target: rtSla.target_ms,
    message: `Response time ${currentDuration}ms approaching SLA threshold`
  });
}

slaStatus.response_time = {
  current_ms: currentDuration,
  target_ms: rtSla.target_ms,
  status: currentDuration <= rtSla.target_ms ? 'ok' :
          currentDuration <= rtSla.warning_ms ? 'warning' : 'violation',
  percent_of_target: Math.round((currentDuration / rtSla.target_ms) * 100)
};

// Overall SLA health
const overallStatus = slaViolations.length > 0 ? 'violation' :
                      slaWarnings.length > 0 ? 'warning' : 'ok';

return {
  json: {
    ...input,
    sla: {
      status: overallStatus,
      definitions: SLA_DEFINITIONS,
      current_metrics: slaStatus,
      violations: slaViolations,
      warnings: slaWarnings,

      // SLA report
      report: {
        request_id: input.deduplication?.request_id,
        duration_ms: currentDuration,
        is_error: isError,
        timestamp: new Date().toISOString()
      }
    }
  }
};

// Secret Management - Secure credential storage and rotation
const input = $input.first().json;
const auth = input.auth || {};
const tenant = input.tenant || {};

// Secret management configuration
const SECRET_CONFIG = {
  // Secret types and their rotation policies
  types: {
    api_key: { rotation_days: 90, auto_rotate: false },
    oauth_token: { rotation_days: 30, auto_rotate: true },
    password: { rotation_days: 60, auto_rotate: false },
    certificate: { rotation_days: 365, auto_rotate: true }
  },

  // Access levels
  access_levels: {
    admin: ['*'],
    developer: ['api_key', 'oauth_token'],
    user: ['oauth_token'],
    readonly: []
  }
};

// Simulated secret store (would be Vault/AWS Secrets Manager in production)
const SECRET_STORE = {
  'anthropic_api_key': {
    type: 'api_key',
    created_at: '2026-01-01T00:00:00Z',
    last_rotated: '2026-01-15T00:00:00Z',
    expires_at: '2026-04-15T00:00:00Z',
    access_roles: ['admin', 'developer']
  },
  'google_oauth': {
    type: 'oauth_token',
    created_at: '2026-01-20T00:00:00Z',
    last_rotated: '2026-02-01T00:00:00Z',
    expires_at: '2026-03-01T00:00:00Z',
    access_roles: ['admin', 'developer', 'user']
  },
  'twilio_credentials': {
    type: 'api_key',
    created_at: '2026-01-01T00:00:00Z',
    last_rotated: '2026-01-01T00:00:00Z',
    expires_at: '2026-04-01T00:00:00Z',
    access_roles: ['admin']
  }
};

// Get user's role
const userRole = (auth.roles || ['readonly'])[0];
const allowedTypes = SECRET_CONFIG.access_levels[userRole] || [];
const canAccessAll = allowedTypes.includes('*');

// Check secret health
const secretHealth = [];
const now = new Date();

for (const [name, secret] of Object.entries(SECRET_STORE)) {
  const expiresAt = new Date(secret.expires_at);
  const daysUntilExpiry = Math.ceil((expiresAt - now) / (1000 * 60 * 60 * 24));
  const policy = SECRET_CONFIG.types[secret.type];

  const health = {
    name: name,
    type: secret.type,
    days_until_expiry: daysUntilExpiry,
    rotation_due: daysUntilExpiry < 7,
    expired: daysUntilExpiry < 0,
    auto_rotate: policy.auto_rotate,
    user_can_access: canAccessAll || allowedTypes.includes(secret.type)
  };

  // Add warnings
  if (health.expired) {
    health.status = 'expired';
    health.warning = `Secret ${name} has expired!`;
  } else if (health.rotation_due) {
    health.status = 'rotation_due';
    health.warning = `Secret ${name} expires in ${daysUntilExpiry} days`;
  } else {
    health.status = 'healthy';
  }

  secretHealth.push(health);
}

// Count issues
const expiredSecrets = secretHealth.filter(s => s.expired).length;
const rotationDue = secretHealth.filter(s => s.rotation_due && !s.expired).length;

return {
  json: {
    ...input,
    secrets: {
      user_role: userRole,
      allowed_types: allowedTypes,

      // Health summary
      health: {
        total_secrets: secretHealth.length,
        healthy: secretHealth.filter(s => s.status === 'healthy').length,
        rotation_due: rotationDue,
        expired: expiredSecrets,
        overall_status: expiredSecrets > 0 ? 'critical' : rotationDue > 0 ? 'warning' : 'healthy'
      },

      // Accessible secrets health details
      secrets: secretHealth.filter(s => s.user_can_access),

      // Alerts
      alerts: secretHealth
        .filter(s => s.warning && s.user_can_access)
        .map(s => ({ secret: s.name, message: s.warning, severity: s.status }))
    }
  }
};

// Request Correlation Engine - Link related requests together
const input = $input.first().json;
const headers = input.headers || {};
const body = input.body || {};

// Correlation identifiers
const correlationId = headers['x-correlation-id'] ||
                      headers['x-request-id'] ||
                      input.trace?.trace_id ||
                      `corr_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;

const sessionId = headers['x-session-id'] ||
                  input.auth?.session_id ||
                  `sess_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;

const conversationId = body.conversation_id ||
                       body.thread_id ||
                       `conv_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;

// Parent request tracking (for sub-agent calls)
const parentRequestId = headers['x-parent-request-id'] || null;
const rootRequestId = headers['x-root-request-id'] || correlationId;
const depth = parseInt(headers['x-request-depth'] || '0');

// Build correlation context
const correlation = {
  // Primary identifiers
  correlation_id: correlationId,
  session_id: sessionId,
  conversation_id: conversationId,

  // Hierarchy (for sub-agent tracking)
  parent_request_id: parentRequestId,
  root_request_id: rootRequestId,
  depth: depth,
  is_sub_request: parentRequestId !== null,

  // Propagation headers (to pass to sub-requests)
  propagation_headers: {
    'x-correlation-id': correlationId,
    'x-session-id': sessionId,
    'x-root-request-id': rootRequestId,
    'x-parent-request-id': input.deduplication?.request_id || correlationId,
    'x-request-depth': (depth + 1).toString()
  },

  // Metadata
  created_at: new Date().toISOString(),
  user_id: input.auth?.user || 'anonymous',
  tenant_id: input.tenant?.tenant_id || 'default'
};

// Log correlation for distributed tracing
console.log(JSON.stringify({
  event: 'request_correlation',
  ...correlation
}));

return {
  json: {
    ...input,
    correlation: correlation
  }
};

// Chaos Engineering Controller - Fault injection for testing resilience
const input = $input.first().json;
const headers = input.headers || {};

// Chaos configuration (only enabled in non-production or with special header)
const CHAOS_CONFIG = {
  enabled: headers['x-chaos-enabled'] === 'true',

  // Fault types
  faults: {
    latency: {
      enabled: true,
      probability: 0.1,  // 10% of requests
      min_delay_ms: 500,
      max_delay_ms: 3000
    },
    error: {
      enabled: true,
      probability: 0.05,  // 5% of requests
      error_codes: ['SIMULATED_ERROR', 'CHAOS_FAULT', 'RANDOM_FAILURE']
    },
    timeout: {
      enabled: true,
      probability: 0.02,  // 2% of requests
      timeout_ms: 30000
    },
    resource_exhaustion: {
      enabled: false,
      probability: 0.01
    }
  }
};

// Skip chaos if not enabled
if (!CHAOS_CONFIG.enabled) {
  return {
    json: {
      ...input,
      chaos: {
        enabled: false,
        message: 'Chaos engineering disabled. Set x-chaos-enabled: true to enable.'
      }
    }
  };
}

// Roll dice for each fault type
const faultsTriggered = [];
const random = Math.random();
let totalProbability = 0;

for (const [faultType, config] of Object.entries(CHAOS_CONFIG.faults)) {
  if (!config.enabled) continue;

  totalProbability += config.probability;
  if (random < totalProbability) {
    faultsTriggered.push(faultType);
    break;  // Only trigger one fault at a time
  }
}

// Apply fault effects
let chaosResult = {
  enabled: true,
  faults_triggered: faultsTriggered,
  random_value: random
};

if (faultsTriggered.includes('latency')) {
  const config = CHAOS_CONFIG.faults.latency;
  const delay = Math.floor(Math.random() * (config.max_delay_ms - config.min_delay_ms) + config.min_delay_ms);
  chaosResult.latency_injection = {
    delay_ms: delay,
    message: `Chaos: Injecting ${delay}ms latency`
  };
}

if (faultsTriggered.includes('error')) {
  const config = CHAOS_CONFIG.faults.error;
  const errorCode = config.error_codes[Math.floor(Math.random() * config.error_codes.length)];
  chaosResult.error_injection = {
    error_code: errorCode,
    message: `Chaos: Simulating error ${errorCode}`
  };

  // Return error immediately
  return {
    json: {
      success: false,
      error: errorCode,
      message: 'Chaos engineering fault injection',
      chaos: chaosResult
    }
  };
}

if (faultsTriggered.includes('timeout')) {
  chaosResult.timeout_injection = {
    timeout_ms: CHAOS_CONFIG.faults.timeout.timeout_ms,
    message: 'Chaos: Simulating timeout'
  };
}

return {
  json: {
    ...input,
    chaos: chaosResult
  }
};
